  createdAt: toIsoString(row.createdAt),
  ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
  ...(row.inherited ? { inherited: true } : {}),
} satisfies WorkspaceBootstrapMessage));
```

The `inherited` field is only set when `true`, following the "omit optional fields" convention from AGENTS.md.

---

### Phase 6: LLM Context Building -- Branch-Aware Message History

**File:** `/Users/marcus/conductor/workspaces/brain/boston/app/src/server/chat/chat-processor.ts`

The critical changes are in the `processChatMessage` function.

**6a. Replace the branch detection code (lines 51-57).** Currently:

```typescript
const [branchRows] = await input.deps.surreal
  .query<[Array<{ context_entities: RecordId[] }>]>(
    "SELECT context_entities FROM branched_from WHERE `in` = $conversation LIMIT 1;",
    { conversation: conversationRecord },
  )
  .collect<[...]>();
const inheritedEntityIds = branchRows[0]?.context_entities;
```

Replace with:

```typescript
import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";

const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
const isBranch = branchChain.length > 0;

// Backward compat: load legacy context_entities for old-style branches
let inheritedEntityIds: RecordId[] | undefined;
if (!isBranch) {
  const [branchRows] = await input.deps.surreal
    .query<[Array<{ context_entities: RecordId[] }>]>(
      "SELECT context_entities FROM branched_from WHERE `in` = $conversation LIMIT 1;",
      { conversation: conversationRecord },
    )
    .collect<[...]>();
  inheritedEntityIds = branchRows[0]?.context_entities;
}
```

**6b. Update assistant context loading (line 59).** For branches, load inherited messages and prepend them to the context:

```typescript
let assistantContextRows: MessageContextRow[];
if (isBranch) {
  const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
  // Convert to MessageContextRow format, take last 10 for assistant context
  assistantContextRows = allMessages
    .map((m) => ({
      id: new RecordId("message", m.id),
      role: m.role,
      text: m.text,
      createdAt: m.createdAt,
    }))
    .slice(-10);
} else {
  assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
}
```

**6c. For entity context in branches**, derive `inheritedEntityIds` from extraction_relations on inherited messages. After loading the branch chain:

```typescript
if (isBranch) {
  const inheritedMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 60);
  const inheritedMsgIds = inheritedMessages
    .filter((m) => m.inherited)
    .map((m) => new RecordId("message", m.id));

  if (inheritedMsgIds.length > 0) {
    const [entityRows] = await input.deps.surreal
      .query<[Array<{ out: RecordId }>]>(
        "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
        { msgIds: inheritedMsgIds },
      )
      .collect<[...]>();
    inheritedEntityIds = entityRows.map((r) => r.out);
  }
}
```

This replaces the stored `context_entities` with dynamically derived entity IDs from the actual inherited messages, which is more accurate and automatically stays up to date.

---

### Phase 7: UI -- Per-Message Branch Button and Inherited Message Rendering

**File:** `/Users/marcus/conductor/workspaces/brain/boston/app/src/client/routes/chat-page.tsx`

**7a. Add state for tracking inherited messages and assistant message IDs:**

```typescript
const [inheritedMessageIds, setInheritedMessageIds] = useState<Set<string>>(new Set());
const [assistantMessageMap, setAssistantMessageMap] = useState<Map<string, string>>(new Map());
```

**7b. Update `loadConversation` (line 151-216).** When mapping backend messages to reachat conversations, track inherited IDs and assistant message IDs:

```typescript
const inheritedIds = new Set<string>();
const assistantMap = new Map<string, string>();

for (const message of payload.messages) {
  if (message.inherited) {
    inheritedIds.add(message.id);
  }
  if (message.role === "user") {
    conversations.push({
      id: message.id,
      question: message.text,
      createdAt: new Date(message.createdAt),
    });
  } else {
    const last = conversations[conversations.length - 1];
    if (last && !last.response) {
      last.response = message.text;
      last.updatedAt = new Date(message.createdAt);
      assistantMap.set(last.id, message.id);  // Track assistant message ID
      if (message.inherited) {
        inheritedIds.add(last.id);  // Mark the pair as inherited
      }
      // ...
    }
  }
}

setInheritedMessageIds(inheritedIds);
setAssistantMessageMap(assistantMap);
```

Do the same in `applyBootstrapPayload`.

**7c. Update `onBranchConversation` to accept a `messageId` parameter:**

```typescript
async function onBranchFromMessage(conversationPairId: string) {
  if (!workspace || !activeConversationId || isLoading) return;

  // Resolve the actual message ID (prefer assistant message if available)
  const targetMessageId = assistantMessageMap.get(conversationPairId) ?? conversationPairId;

  setBranchingFromId(conversationPairId);
  try {
    const response = await fetch(
      `/api/workspaces/${encodeURIComponent(workspace.id)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ messageId: targetMessageId }),
      },
    );
    // ... same error handling and loadConversation call
  } finally {
    setBranchingFromId(undefined);
  }
}
```

**7d. Remove the conversation-level branch button** from `SessionMessagesHeader` (lines 872-881).

**7e. Add per-message branch button** in the `SessionMessages` render (lines 884-895):

```tsx
<SessionMessages>
  {(conversations) =>
    conversations.map((conversation, index) => {
      const isInherited = inheritedMessageIds.has(conversation.id);
      return (
        <div
          key={conversation.id}
          data-message-id={conversation.id}
          className={isInherited ? "message-inherited" : undefined}
        >
          <SessionMessage
            conversation={conversation}
            isLast={index === conversations.length - 1}
          />
          {!isInherited && workspace.onboardingState === "complete" && conversation.response ? (
            <button
              type="button"
              className="branch-message-btn"
              onClick={() => void onBranchFromMessage(conversation.id)}
              disabled={isLoading || branchingFromId !== undefined}
            >
              {branchingFromId === conversation.id ? "Branching..." : "Branch from here"}
            </button>
          ) : undefined}
        </div>
