372→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
373→  LET $query = string::lowercase(string::trim($q));
374→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
375→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
376→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
377→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
378→
379→  LET $task_rows = SELECT
380→    id,
381→    "task" AS kind,
382→    title AS text,
383→    extraction_confidence AS confidence,
384→    source_message AS sourceMessage,
385→    created_at
386→  FROM task
387→  WHERE source_message != NONE
388→    AND source_message IN $workspace_messages
389→    AND extraction_confidence != NONE
390→    AND id IN $project_entity_ids
391→    AND string::contains(string::lowercase(title), $query)
392→  ORDER BY created_at DESC
393→  LIMIT $safe_limit;
394→
395→  LET $decision_rows = SELECT
396→    id,
397→    "decision" AS kind,
398→    summary AS text,
399→    extraction_confidence AS confidence,
400→    source_message AS sourceMessage,
401→    created_at
402→  FROM decision
403→  WHERE source_message != NONE
404→    AND source_message IN $workspace_messages
405→    AND extraction_confidence != NONE
406→    AND id IN $project_entity_ids
407→    AND string::contains(string::lowercase(summary), $query)
408→  ORDER BY created_at DESC
409→  LIMIT $safe_limit;
410→
411→  LET $question_rows = SELECT
412→    id,
413→    "question" AS kind,
414→    text AS text,
415→    extraction_confidence AS confidence,
416→    source_message AS sourceMessage,
417→    created_at
418→  FROM question
