439→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
440→  RETURN SELECT
441→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
442→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
443→  FROM $entity;
444→};
