 48→
 49→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations] = await Promise.all([
 50→    loaders.listConversationEntities({
 51→      surreal: input.surreal,
 52→      conversationRecord: input.conversationRecord,
 53→      workspaceRecord: input.workspaceRecord,
 54→      limit: 60,
 55→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 56→        ? { inheritedEntityIds: input.inheritedEntityIds }
 57→        : {}),
 58→    }),
 59→    loaders.listWorkspaceProjectSummaries({
 60→      surreal: input.surreal,
 61→      workspaceRecord: input.workspaceRecord,
 62→      limit: 20,
