127→
128→function formatQuestionList(questions: WorkspaceQuestionSummary[]): string {
129→  if (questions.length === 0) {
130→    return "- none";
131→  }
132→
133→  return questions
134→    .slice(0, 15)
135→    .map((question) => {
136→      const project = question.project ? ` project: ${question.project}` : "";
137→      return `- ${question.name} [id: ${question.id}]${project}`;
138→    })
139→    .join("\n");
140→}
141→
142→function formatObservationList(observations: ObservationSummary[]): string {
143→  if (observations.length === 0) {
144→    return "- none";
145→  }
146→
147→  return observations
148→    .slice(0, 10)
149→    .map((observation) => {
150→      const category = observation.category ? `, ${observation.category}` : "";
151→      return `- [${observation.severity}] ${observation.text} (by ${observation.sourceAgent}, ${observation.status}${category})`;
152→    })
