318→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
319→  LET $query = string::lowercase(string::trim($q));
320→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
321→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
322→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
323→
324→  LET $task_rows = SELECT
325→    id,
326→    "task" AS kind,
327→    title AS text,
328→    extraction_confidence AS confidence,
329→    source_message AS sourceMessage,
330→    created_at
331→  FROM task
332→  WHERE source_message != NONE
333→    AND source_message IN $workspace_messages
334→    AND extraction_confidence != NONE
335→    AND string::contains(string::lowercase(title), $query)
336→  ORDER BY created_at DESC
337→  LIMIT $safe_limit;
338→
339→  LET $decision_rows = SELECT
340→    id,
341→    "decision" AS kind,
342→    summary AS text,
343→    extraction_confidence AS confidence,
344→    source_message AS sourceMessage,
345→    created_at
346→  FROM decision
347→  WHERE source_message != NONE
348→    AND source_message IN $workspace_messages
349→    AND extraction_confidence != NONE
350→    AND string::contains(string::lowercase(summary), $query)
351→  ORDER BY created_at DESC
352→  LIMIT $safe_limit;
353→
354→  LET $question_rows = SELECT
355→    id,
356→    "question" AS kind,
357→    text AS text,
358→    extraction_confidence AS confidence,
359→    source_message AS sourceMessage,
360→    created_at
361→  FROM question
362→  WHERE source_message != NONE
363→    AND source_message IN $workspace_messages
364→    AND extraction_confidence != NONE
365→    AND string::contains(string::lowercase(text), $query)
366→  ORDER BY created_at DESC
367→  LIMIT $safe_limit;
368→
369→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
370→};
