213→/**
214→ * Refreshes the touched_by edges for a conversation based on its extraction_relation rows.
215→ */
216→export async function refreshConversationTouchedBy(
217→  surreal: Surreal,
218→  conversationRecord: RecordId<"conversation", string>,
219→): Promise<void> {
220→  const [extractionRows] = await surreal
221→    .query<[ExtractionEdgeRow[]]>(
222→      "SELECT out, extracted_at FROM extraction_relation WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation);",
223→      { conversation: conversationRecord },
224→    )
225→    .collect<[ExtractionEdgeRow[]]>();
226→
227→  // Aggregate: projectId -> { uniqueEntityIds, earliestExtractedAt }
228→  const projectAgg = new Map<string, { entityIds: Set<string>; earliestAt: Date }>();
229→
230→  for (const row of extractionRows) {
231→    const projects = await resolveEntityToProjects(surreal, row.out);
232→    const extractedAt = row.extracted_at instanceof Date ? row.extracted_at : new Date(row.extracted_at as string);
233→    const entityId = `${row.out.tb}:${row.out.id}`;
234→
235→    for (const projectRecord of projects) {
236→      const projectId = projectRecord.id as string;
237→      const existing = projectAgg.get(projectId);
238→      if (existing) {
239→        existing.entityIds.add(entityId);
240→        if (extractedAt < existing.earliestAt) {
241→          existing.earliestAt = extractedAt;
242→        }
243→      } else {
244→        projectAgg.set(projectId, {
245→          entityIds: new Set([entityId]),
246→          earliestAt: extractedAt,
247→        });
248→      }
249→    }
250→  }
251→
252→  // Load existing touched_by edges for this conversation
253→  const [existingEdges] = await surreal
254→    .query<[TouchedByRow[]]>(
255→      "SELECT id, `in`, out, entity_count, first_mention_at FROM touched_by WHERE out = $conversation;",
256→      { conversation: conversationRecord },
257→    )
258→    .collect<[TouchedByRow[]]>();
259→
260→  const existingByProject = new Map<string, TouchedByRow>();
261→  for (const edge of existingEdges) {
262→    existingByProject.set(edge.in.id as string, edge);
263→  }
264→
265→  // Upsert edges for current project aggregations
266→  for (const [projectId, agg] of projectAgg) {
267→    const existing = existingByProject.get(projectId);
268→    const entityCount = agg.entityIds.size;
269→
270→    if (existing) {
271→      await surreal.update(existing.id).merge({
272→        entity_count: entityCount,
273→        first_mention_at: agg.earliestAt,
274→      });
275→      existingByProject.delete(projectId);
276→    } else {
277→      const projectRecord = new RecordId("project", projectId);
278→      await surreal.relate(
279→        projectRecord,
280→        new RecordId("touched_by", randomUUID()),
281→        conversationRecord,
282→        {
283→          first_mention_at: agg.earliestAt,
284→          entity_count: entityCount,
285→        },
286→      ).output("after");
287→    }
288→  }
289→
290→  // Remove stale edges (projects no longer represented)
291→  for (const staleEdge of existingByProject.values()) {
292→    await surreal.delete(staleEdge.id);
293→  }
294→
295→  logInfo("conversation.touched_by.refreshed", "Refreshed touched_by edges", {
296→    conversationId: conversationRecord.id as string,
297→    projectCount: projectAgg.size,
298→    removedCount: existingByProject.size,
299→  });
300→}
