410→type ConversationSidebarRow = {
411→  id: RecordId<"conversation", string>;
412→  title?: string;
413→  updatedAt: Date | string;
414→};
415→
416→type FeatureActivityRow = {
417→  featureId: RecordId<"feature", string>;
418→  featureName: string;
419→  latestActivityAt: Date | string;
420→};
