442→export async function buildWorkspaceConversationSidebar(
443→  surreal: Surreal,
444→  workspaceRecord: RecordId<"workspace", string>,
445→): Promise<WorkspaceConversationSidebarResponse> {
446→  // Load all conversations for this workspace
447→  const [conversationRows] = await surreal
448→    .query<[ConversationSidebarRow[]]>(
449→      "SELECT id, title, updatedAt FROM conversation WHERE workspace = $workspace ORDER BY updatedAt DESC;",
450→      { workspace: workspaceRecord },
451→    )
452→    .collect<[ConversationSidebarRow[]]>();
453→
454→  // Load all touched_by edges for these conversations
455→  const conversationIds = conversationRows.map((row) => row.id);
456→  const [touchedByRows] = await surreal
457→    .query<[TouchedByRow[]]>(
458→      "SELECT id, `in`, out, entity_count, first_mention_at FROM touched_by WHERE out IN $conversations;",
459→      { conversations: conversationIds },
460→    )
461→    .collect<[TouchedByRow[]]>();
462→
463→  // Load branched_from edges to build parent/child relationships
464→  const [branchEdges] = await surreal
465→    .query<[BranchedFromRow[]]>(
466→      "SELECT `in`, out FROM branched_from WHERE `in` IN $conversations;",
467→      { conversations: conversationIds },
468→    )
469→    .collect<[BranchedFromRow[]]>();
470→
471→  // Build branch parent/child maps
472→  const parentMap = new Map<string, string>();
473→  for (const edge of branchEdges) {
474→    parentMap.set(edge.in.id as string, edge.out.id as string);
475→  }
476→
477→  // Build touched_by lookup by conversation
478→  const touchedByMap = new Map<string, Array<{ projectId: string; entityCount: number }>>();
479→  for (const row of touchedByRows) {
480→    const convId = row.out.id as string;
481→    const existing = touchedByMap.get(convId) ?? [];
482→    existing.push({ projectId: row.in.id as string, entityCount: row.entity_count });
483→    touchedByMap.set(convId, existing);
484→  }
485→
486→  // Build sidebar items for ALL conversations (including branches)
487→  const allItems = new Map<string, ConversationSidebarItem>();
488→  for (const row of conversationRows) {
489→    const id = row.id.id as string;
490→    allItems.set(id, {
491→      id,
492→      title: row.title ?? "Untitled",
493→      updatedAt: toIsoString(row.updatedAt),
494→      ...(parentMap.has(id) ? { parentId: parentMap.get(id) } : {}),
495→    });
496→  }
497→
498→  // Build children lookup (parentId -> child items)
499→  const childrenMap = new Map<string, ConversationSidebarItem[]>();
500→  for (const [childId, parentId] of parentMap) {
501→    const childItem = allItems.get(childId);
502→    if (!childItem) continue;
503→    const children = childrenMap.get(parentId) ?? [];
504→    children.push(childItem);
505→    childrenMap.set(parentId, children);
506→  }
507→
508→  // Only group root conversations (those without a parent)
509→  const conversationInputs: ConversationGroupInput[] = conversationRows
510→    .filter((row) => !parentMap.has(row.id.id as string))
511→    .map((row) => ({
512→      id: row.id.id as string,
513→      title: row.title,
514→      updatedAt: toIsoString(row.updatedAt),
515→      touchedBy: touchedByMap.get(row.id.id as string) ?? [],
516→    }));
517→
518→  const { groups, unlinked } = groupConversationsByProject(conversationInputs);
519→
520→  // Load project names and build groups, attaching branches
521→  const projectGroups: ProjectConversationGroup[] = [];
522→  for (const [projectId, conversations] of groups) {
523→    const projectRecord = new RecordId("project", projectId);
524→    const project = await surreal.select<{ name: string }>(projectRecord);
525→    if (!project) continue;
526→
527→    const withBranches = conversations.map((conv) => attachBranches(conv, childrenMap));
528→    const featureActivity = await loadProjectFeatureActivity(surreal, projectRecord, withBranches);
529→
530→    projectGroups.push({
531→      projectId,
532→      projectName: project.name,
533→      conversations: withBranches,
534→      featureActivity,
535→    });
536→  }
537→
538→  const unlinkedWithBranches = unlinked.map((conv) => attachBranches(conv, childrenMap));
539→
540→  return { groups: projectGroups, unlinked: unlinkedWithBranches };
541→}
