543→async function loadProjectFeatureActivity(
544→  surreal: Surreal,
545→  projectRecord: RecordId<"project", string>,
546→  _conversations: ConversationSidebarItem[],
547→): Promise<ProjectFeatureActivity[]> {
548→  // Get features for this project with latest extraction activity
549→  const [rows] = await surreal
550→    .query<[FeatureActivityRow[]]>(
551→      [
552→        "SELECT out.id AS featureId, out.name AS featureName, math::max(extracted_at) AS latestActivityAt",
553→        "FROM extraction_relation",
554→        "WHERE out IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
555→        "GROUP BY out",
556→        "ORDER BY latestActivityAt DESC",
557→        "LIMIT 5;",
558→      ].join(" "),
559→      { project: projectRecord },
560→    )
561→    .collect<[FeatureActivityRow[]]>();
562→
563→  return rows.map((row) => ({
564→    featureId: (row.featureId as unknown as RecordId<"feature", string>).id as string,
565→    featureName: row.featureName,
566→    latestActivityAt: toIsoString(row.latestActivityAt),
567→  }));
568→}
