151→  async function loadConversation(workspaceId: string, conversationId: string) {
152→    try {
153→      const response = await fetch(
154→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(conversationId)}`,
155→      );
156→      if (!response.ok) {
157→        const body = await response.text();
158→        setErrorMessage(body);
159→        return;
160→      }
161→
162→      const payload = (await response.json()) as WorkspaceConversationResponse;
163→      const conversations: Session["conversations"] = [];
164→      let latestSuggestions: string[] = [];
165→
166→      for (const message of payload.messages) {
167→        if (message.role === "user") {
168→          conversations.push({
169→            id: message.id,
170→            question: message.text,
171→            createdAt: new Date(message.createdAt),
172→          });
173→          continue;
174→        }
175→
176→        const last = conversations[conversations.length - 1];
177→        if (last && !last.response) {
178→          last.response = message.text;
179→          last.updatedAt = new Date(message.createdAt);
180→          latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
181→          continue;
182→        }
183→
184→        conversations.push({
185→          id: `assistant-${message.id}`,
186→          question: "System kickoff",
187→          response: message.text,
188→          createdAt: new Date(message.createdAt),
189→        });
190→        latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
191→      }
192→
193→      setSessions([
194→        {
195→          id: "main",
196→          title: workspace?.name ?? "Workspace Chat",
197→          createdAt: new Date(),
198→          updatedAt: new Date(),
199→          conversations,
200→        },
201→      ]);
202→
203→      setSuggestions(
204→        latestSuggestions.map((content, index) => ({
205→          id: `conv-suggestion-${index}-${content}`,
206→          content,
207→        })),
208→      );
209→
210→      setActiveConversationId(conversationId);
211→      setBackendConversationId(conversationId);
212→    } catch (error) {
213→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
214→      setErrorMessage(messageText);
215→    }
216→  }
