147→export function parseRecordIdString<T extends string>(
148→  value: string,
149→  allowedTables: T[],
150→  fallbackTable?: T,
151→): RecordId<T, string> {
152→  const normalized = value.trim();
153→  if (normalized.length === 0) {
154→    throw new Error("record id is required");
155→  }
156→
157→  const separatorIndex = normalized.indexOf(":");
158→  if (separatorIndex === -1) {
159→    if (!fallbackTable) {
160→      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
161→    }
162→
163→    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
164→  }
165→
166→  const table = normalized.slice(0, separatorIndex) as T;
167→  const id = normalized.slice(separatorIndex + 1);
168→  if (!allowedTables.includes(table)) {
169→    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
170→  }
171→
172→  if (id.length === 0) {
173→    throw new Error("record id is missing its identifier component");
174→  }
175→
176→  return new RecordId(table, id) as RecordId<T, string>;
177→}
