287→async function loadWorkspaceSeeds(
288→  deps: ServerDependencies,
289→  workspaceRecord: RecordId<"workspace", string>,
290→  limit: number,
291→): Promise<OnboardingSeedItem[]> {
292→  const [edgeRows] = await deps.surreal
293→    .query<[ProvenanceEdgeRow[]]>(
294→      [
295→        "SELECT id, `in`, out, confidence, extracted_at",
296→        "FROM extraction_relation",
297→        "WHERE `in` IN array::concat(",
298→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
299→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
300→        ")",
301→        "ORDER BY extracted_at DESC",
302→        "LIMIT $limit;",
303→      ].join(" "),
304→      {
305→        workspace: workspaceRecord,
306→        limit,
307→      },
308→    )
309→    .collect<[ProvenanceEdgeRow[]]>();
310→
311→  const items: OnboardingSeedItem[] = [];
312→
313→  for (const edge of edgeRows) {
314→    const entityText = await readEntityText(deps.surreal, edge.out);
315→    if (!entityText) {
316→      continue;
317→    }
318→
319→    const sourceTable = edge.in.tb;
320→    const entityTable = edge.out.tb;
321→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
322→    const sourceLabel = await readSourceLabel(deps, edge.in);
323→
324→    items.push({
325→      id: edge.out.id as string,
326→      kind: entityTable as EntityKind,
327→      text: entityText,
328→      confidence: edge.confidence,
329→      sourceKind,
330→      sourceId: edge.in.id as string,
331→      ...(sourceLabel ? { sourceLabel } : {}),
332→    });
333→  }
334→
335→  return items;
336→}
337→
338→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
339→  const sourceTable = sourceRecord.tb;
340→  if (sourceTable === "message") {
341→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
342→    if (!row) {
343→      return undefined;
344→    }
345→    return row.text.slice(0, 140);
346→  }
347→
348→  const chunk = await deps.surreal.select<{
349→    section_heading?: string;
350→    document: RecordId<"document", string>;
351→  }>(sourceRecord);
352→
353→  if (!chunk) {
354→    return undefined;
355→  }
356→
357→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
358→  if (!document) {
359→    return chunk.section_heading;
360→  }
361→
362→  if (chunk.section_heading) {
363→    return `${document.name} · ${chunk.section_heading}`;
364→  }
365→
366→  return document.name;
367→}
