 76→/**
 77→ * Derives the initial title for a conversation from the first user message.
 78→ */
 79→export function deriveMessageTitle(text: string): string {
 80→  const trimmed = text.trim();
 81→  if (trimmed.length <= 72) {
 82→    return trimmed;
 83→  }
 84→  return `${trimmed.slice(0, 69)}...`;
 85→}
