 87→export type TitleUpgradeInput = {
 88→  titleSource?: "message" | "entity";
 89→  entityTexts: Array<{ kind: string; text: string }>;
 90→  dominantProjectName?: string;
 91→};
 92→
 93→/**
 94→ * Determines whether a conversation title should be upgraded and returns
 95→ * the new title if so. Returns undefined if no upgrade should happen.
 96→ */
 97→export function computeTitleUpgrade(input: TitleUpgradeInput): string | undefined {
 98→  if (input.titleSource !== "message") {
 99→    return undefined;
100→  }
101→
102→  const qualifying = input.entityTexts.filter(
103→    (entity) => entity.kind !== "person" && entity.kind !== "workspace",
104→  );
105→
106→  if (qualifying.length < 3) {
107→    return undefined;
108→  }
109→
110→  if (input.dominantProjectName) {
111→    return deriveMessageTitle(input.dominantProjectName);
112→  }
113→
114→  // Use the most common entity text as fallback
115→  const counts = new Map<string, number>();
116→  for (const entity of qualifying) {
117→    const key = entity.text.toLowerCase();
118→    counts.set(key, (counts.get(key) ?? 0) + 1);
119→  }
120→
121→  let bestText = qualifying[0].text;
122→  let bestCount = 0;
123→  for (const [key, count] of counts) {
124→    if (count > bestCount) {
125→      bestCount = count;
126→      bestText = qualifying.find((e) => e.text.toLowerCase() === key)?.text ?? bestText;
127→    }
128→  }
129→
130→  return deriveMessageTitle(bestText);
131→}
