302→/**
303→ * Upgrades a conversation title if conditions are met (title_source === "message",
304→ * >= 3 qualifying entities extracted).
305→ */
306→export async function maybeUpgradeConversationTitle(
307→  surreal: Surreal,
308→  conversationRecord: RecordId<"conversation", string>,
309→): Promise<void> {
310→  const conversation = await surreal.select<{
311→    title?: string;
312→    title_source?: "message" | "entity";
313→  }>(conversationRecord);
314→
315→  if (!conversation || conversation.title_source !== "message") {
316→    return;
317→  }
318→
319→  // Count qualifying extracted entities for this conversation
320→  const [entityRows] = await surreal
321→    .query<[Array<{ out: GraphEntityRecord }>]>(
322→      "SELECT out FROM extraction_relation WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation);",
323→      { conversation: conversationRecord },
324→    )
325→    .collect<[Array<{ out: GraphEntityRecord }>]>();
326→
327→  const uniqueEntities = new Map<string, { kind: string; text: string }>();
328→  for (const row of entityRows) {
329→    const key = `${row.out.tb}:${row.out.id}`;
330→    if (!uniqueEntities.has(key)) {
331→      uniqueEntities.set(key, { kind: row.out.tb, text: "" });
332→    }
333→  }
334→
335→  const qualifying = [...uniqueEntities.values()].filter(
336→    (e) => e.kind !== "person" && e.kind !== "workspace",
337→  );
338→
339→  if (qualifying.length < 3) {
340→    return;
341→  }
342→
343→  // Check for dominant project via touched_by
344→  const [touchedByRows] = await surreal
345→    .query<[Array<{ in: RecordId<"project", string>; entity_count: number }>]>(
346→      "SELECT `in`, entity_count FROM touched_by WHERE out = $conversation;",
347→      { conversation: conversationRecord },
348→    )
349→    .collect<[Array<{ in: RecordId<"project", string>; entity_count: number }>]>();
350→
351→  let dominantProjectName: string | undefined;
352→  if (touchedByRows.length > 0) {
353→    const total = touchedByRows.reduce((sum, row) => sum + row.entity_count, 0);
354→    let topRow = touchedByRows[0];
355→    for (const row of touchedByRows) {
356→      if (row.entity_count > topRow.entity_count) {
357→        topRow = row;
358→      }
359→    }
360→
361→    if (topRow.entity_count > total / 2) {
362→      const project = await surreal.select<{ name: string }>(topRow.in);
363→      if (project) {
364→        dominantProjectName = project.name;
365→      }
366→    }
367→  }
368→
369→  // Get entity texts for fallback title
370→  const entityTexts: Array<{ kind: string; text: string }> = [];
371→  for (const [, entry] of uniqueEntities) {
372→    entityTexts.push(entry);
373→  }
374→
375→  // Need actual texts from entities
376→  const entityTextRows: Array<{ kind: string; text: string }> = [];
377→  for (const row of entityRows) {
378→    const kind = row.out.tb;
379→    if (kind === "person" || kind === "workspace") continue;
380→
381→    const textField = kind === "task" ? "title" : kind === "decision" ? "summary" : "text";
382→    const entity = await surreal.select<Record<string, string>>(row.out);
383→    if (entity) {
384→      const text = entity[textField] ?? entity.name ?? "";
385→      entityTextRows.push({ kind, text });
386→    }
387→  }
388→
389→  const newTitle = computeTitleUpgrade({
390→    titleSource: "message",
391→    entityTexts: entityTextRows,
392→    dominantProjectName,
393→  });
394→
395→  if (newTitle) {
396→    await surreal.update(conversationRecord).merge({
397→      title: newTitle,
398→      title_source: "entity" as const,
399→    });
400→
401→    logInfo("conversation.title.upgraded", "Upgraded conversation title", {
402→      conversationId: conversationRecord.id as string,
403→      newTitle,
404→    });
405→  }
406→}
