  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import { z } from "zod";
  4→import type { BranchConversationResponse } from "../../shared/contracts";
  5→import type { ConversationRow } from "../extraction/types";
  6→import { loadConversationGraphContext } from "../extraction/context-loaders";
  7→import { HttpError } from "../http/errors";
  8→import { logError, logInfo, logWarn } from "../http/observability";
  9→import { jsonError, jsonResponse } from "../http/response";
 10→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 11→import { deriveMessageTitle } from "../workspace/conversation-sidebar";
 12→import type { ServerDependencies } from "../runtime/types";
 13→
 14→const ENTITY_TABLES = ["task", "decision", "question", "feature", "project", "person"] as const;
 15→
 16→const branchRequestSchema = z.object({
 17→  contextEntityIds: z.array(z.string()).default([]),
 18→});
 19→
 20→export function createBranchConversationHandler(
 21→  deps: ServerDependencies,
 22→): (workspaceId: string, parentConversationId: string, request: Request) => Promise<Response> {
 23→  return (workspaceId: string, parentConversationId: string, request: Request) =>
 24→    handleBranchConversation(deps, workspaceId, parentConversationId, request);
 25→}
 26→
 27→async function handleBranchConversation(
 28→  deps: ServerDependencies,
 29→  workspaceId: string,
 30→  parentConversationId: string,
 31→  request: Request,
 32→): Promise<Response> {
 33→  let body: unknown;
 34→  try {
 35→    body = await request.json();
 36→  } catch {
 37→    return jsonError("invalid JSON body", 400);
 38→  }
 39→
 40→  const parsed = branchRequestSchema.safeParse(body);
 41→  if (!parsed.success) {
 42→    return jsonError(`invalid branch request: ${parsed.error.message}`, 400);
 43→  }
 44→
 45→  let workspaceRecord: RecordId<"workspace", string>;
 46→  try {
 47→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 48→  } catch (error) {
 49→    if (error instanceof HttpError) {
 50→      return jsonError(error.message, error.status);
 51→    }
 52→    logError("branch.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 53→    return jsonError("failed to resolve workspace", 500);
 54→  }
 55→
 56→  try {
 57→    const parentRecord = new RecordId("conversation", parentConversationId);
 58→    const parent = await deps.surreal.select<ConversationRow>(parentRecord);
 59→    if (!parent) {
 60→      throw new HttpError(404, `conversation not found: ${parentConversationId}`);
 61→    }
 62→
 63→    if ((parent.workspace.id as string) !== (workspaceRecord.id as string)) {
 64→      throw new HttpError(400, "conversation does not belong to workspace");
 65→    }
 66→
 67→    // Resolve context entity records
 68→    let contextEntityRecords: RecordId[] = [];
 69→
 70→    if (parsed.data.contextEntityIds.length > 0) {
 71→      // Parse provided entity IDs, skip invalid ones
 72→      for (const idString of parsed.data.contextEntityIds) {
 73→        const normalized = idString.trim();
 74→        const separatorIndex = normalized.indexOf(":");
 75→        if (separatorIndex === -1) continue;
 76→
 77→        const table = normalized.slice(0, separatorIndex);
 78→        const id = normalized.slice(separatorIndex + 1);
 79→        if (!(ENTITY_TABLES as readonly string[]).includes(table) || id.length === 0) continue;
 80→
 81→        contextEntityRecords.push(new RecordId(table, id));
 82→      }
 83→    } else {
 84→      // Auto-populate from parent conversation's extracted entities
 85→      const parentEntities = await loadConversationGraphContext(deps.surreal, parentConversationId, 30);
 86→      contextEntityRecords = parentEntities.map((row) => row.id as RecordId);
 87→    }
 88→
 89→    const now = new Date();
 90→    const branchId = randomUUID();
 91→    const branchRecord = new RecordId("conversation", branchId);
 92→    const edgeRecord = new RecordId("branched_from", randomUUID());
 93→
 94→    const branchTitle = parent.title
 95→      ? deriveMessageTitle(`Branch of: ${parent.title}`)
 96→      : "Branch";
 97→
 98→    const transaction = await deps.surreal.beginTransaction();
 99→    try {
100→      await transaction.create(branchRecord).content({
101→        createdAt: now,
102→        updatedAt: now,
103→        workspace: workspaceRecord,
104→        title: branchTitle,
105→        title_source: "message",
106→      });
107→
108→      await transaction
109→        .relate(branchRecord, edgeRecord, parentRecord, {
110→          branched_at: now,
111→          context_entities: contextEntityRecords,
112→        })
113→        .output("after");
114→
115→      await transaction.commit();
116→    } catch (error) {
117→      await transaction.cancel();
118→      throw error;
119→    }
120→
121→    logInfo("branch.created", "Conversation branch created", {
122→      workspaceId,
123→      parentConversationId,
124→      branchId,
125→      contextEntityCount: contextEntityRecords.length,
126→    });
127→
128→    const response: BranchConversationResponse = {
129→      conversationId: branchId,
130→      parentConversationId,
131→    };
132→
133→    return jsonResponse(response, 201);
134→  } catch (error) {
135→    if (error instanceof HttpError) {
136→      logWarn("branch.http_error", "Branch creation failed with client-facing error", {
137→        workspaceId,
138→        parentConversationId,
139→        statusCode: error.status,
140→      });
141→      return jsonError(error.message, error.status);
142→    }
143→
144→    logError("branch.failed", "Branch creation failed", error, {
145→      workspaceId,
146→      parentConversationId,
147→    });
148→    const message = error instanceof Error ? error.message : "branch creation failed";
149→    return jsonError(message, 500);
150→  }
151→}
