 19→export async function processChatMessage(input: {
 20→  deps: ServerDependencies;
 21→  conversationId: string;
 22→  messageId: string;
 23→  workspaceRecord: RecordId<"workspace", string>;
 24→  userMessageRecord: RecordId<"message", string>;
 25→  userText: string;
 26→  attachment?: IncomingAttachment;
 27→  onboardingAction?: OnboardingAction;
 28→}): Promise<void> {
 29→  const startedAt = performance.now();
 30→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 31→    conversationId: input.conversationId,
 32→    messageId: input.messageId,
 33→    workspaceId: input.workspaceRecord.id as string,
 34→    hasAttachment: input.attachment !== undefined,
 35→  });
 36→
 37→  try {
 38→    const now = new Date();
 39→    const conversationRecord = new RecordId("conversation", input.conversationId);
 40→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 41→    if (!workspace) {
 42→      throw new Error("workspace not found");
 43→    }
 44→
 45→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 46→    if (!conversation) {
 47→      throw new Error("conversation not found");
 48→    }
 49→
 50→    // Check if this conversation is a branch and load inherited context
 51→    const [branchRows] = await input.deps.surreal
 52→      .query<[Array<{ context_entities: RecordId[] }>]>(
 53→        "SELECT context_entities FROM branched_from WHERE `in` = $conversation LIMIT 1;",
 54→        { conversation: conversationRecord },
 55→      )
 56→      .collect<[Array<{ context_entities: RecordId[] }>]>();
 57→    const inheritedEntityIds = branchRows[0]?.context_entities;
 58→
 59→    const assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 60→    const extractionConversationContext = await loadExtractionConversationContext({
 61→      surreal: input.deps.surreal,
 62→      conversationId: input.conversationId,
 63→      currentMessageRecord: input.userMessageRecord,
 64→    });
 65→    const extractionGraphContext = await loadConversationGraphContext(
 66→      input.deps.surreal,
 67→      input.conversationId,
 68→      60,
 69→      inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : undefined,
 70→    );
 71→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
 72→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
 73→    const persistedEntities: ExtractedEntity[] = [];
 74→    const persistedRelationships: ExtractedRelationship[] = [];
 75→    const seedItems: OnboardingSeedItem[] = [];
 76→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 77→    const extractedTools: string[] = [];
 78→    const unresolvedAssigneeNames = new Set<string>();
 79→
 80→    if (input.attachment) {
 81→      const ingestion = await ingestAttachment({
 82→        surreal: input.deps.surreal,
 83→        extractionModel: input.deps.extractionModel,
 84→        embeddingModel: input.deps.embeddingModel,
 85→        embeddingDimension: input.deps.config.embeddingDimension,
 86→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
 87→        extractionModelId: input.deps.config.extractionModelId,
 88→        workspaceRecord: input.workspaceRecord,
 89→        conversationRecord,
 90→        userMessageRecord: input.userMessageRecord,
 91→        attachment: input.attachment,
 92→        workspaceName: workspace.name,
 93→        projectNames: workspaceProjectNames,
 94→        now,
 95→        onChunkResult: (chunkResult) => {
 96→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
 97→            input.deps.sse.emitEvent(input.messageId, {
 98→              type: "extraction",
 99→              messageId: input.messageId,
100→              entities: chunkResult.entities,
101→              relationships: chunkResult.relationships,
102→            });
103→          }
104→          if (chunkResult.seeds.length > 0) {
105→            input.deps.sse.emitEvent(input.messageId, {
106→              type: "onboarding_seed",
107→              messageId: input.messageId,
108→              seeds: chunkResult.seeds,
109→            });
110→          }
111→        },
112→      });
113→
114→      persistedEntities.push(...ingestion.entities);
115→      persistedRelationships.push(...ingestion.relationships);
116→      seedItems.push(...ingestion.seeds);
117→      embeddingTargets.push(...ingestion.embeddingTargets);
118→      extractedTools.push(...ingestion.tools);
119→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
120→        unresolvedAssigneeNames.add(unresolvedName);
121→      }
122→    }
123→
124→    const textExtraction = await extractStructuredGraph({
125→      extractionModel: input.deps.extractionModel,
126→      conversationHistory: extractionConversationContext.conversationHistory,
127→      currentMessage: extractionConversationContext.currentMessage,
128→      graphContext: extractionGraphContext,
129→      sourceText: input.userText,
130→      onboarding: !workspace.onboarding_complete,
131→      workspaceName: workspace.name,
132→      projectNames: workspaceProjectNames,
133→    });
134→
135→    const textPersistence = await persistExtractionOutput({
136→      surreal: input.deps.surreal,
137→      embeddingModel: input.deps.embeddingModel,
138→      embeddingDimension: input.deps.config.embeddingDimension,
139→      extractionModelId: input.deps.config.extractionModelId,
140→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
141→      workspaceRecord: input.workspaceRecord,
142→      sourceRecord: input.userMessageRecord as SourceRecord,
143→      sourceKind: "message",
144→      sourceLabel: input.userText.slice(0, 140),
145→      promptText: input.userText,
146→      output: textExtraction,
147→      sourceMessageRecord: input.userMessageRecord,
148→      extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map((row) => row.id.id as string),
149→      now,
150→    });
151→
152→    persistedEntities.push(...textPersistence.entities);
153→    persistedRelationships.push(...textPersistence.relationships);
154→    seedItems.push(...textPersistence.seeds);
155→    embeddingTargets.push(...textPersistence.embeddingTargets);
156→    extractedTools.push(...textPersistence.tools);
157→    for (const unresolvedName of textPersistence.unresolvedAssigneeNames) {
158→      unresolvedAssigneeNames.add(unresolvedName);
159→    }
160→
161→    const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
162→    await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
163→
164→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
165→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
166→
167→    const onboardingBefore = workspace.onboarding_complete
168→      ? "complete"
169→      : workspace.onboarding_summary_pending
170→        ? "summary_pending"
171→        : "active";
172→
173→    const onboardingAfter = await transitionOnboardingState({
174→      surreal: input.deps.surreal,
175→      workspaceRecord: input.workspaceRecord,
176→      workspace,
177→      onboardingAction: input.onboardingAction,
178→      now,
179→    });
180→
181→    let assistantText = "";
182→    let assistantSuggestions: string[] = [];
183→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
184→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
185→    );
186→
187→    if (onboardingAfter === "complete") {
188→      const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
189→        surreal: input.deps.surreal,
190→        workspaceRecord: input.workspaceRecord,
191→      });
192→
193→      const graphAwareResponse = await runOrchestrator({
194→        surreal: input.deps.surreal,
195→        model: input.deps.assistantModel,
196→        pmModel: input.deps.pmModel,
197→        embeddingModel: input.deps.embeddingModel,
198→        embeddingDimension: input.deps.config.embeddingDimension,
199→        extractionModelId: input.deps.config.extractionModelId,
200→        conversationRecord,
201→        workspaceRecord: input.workspaceRecord,
202→        currentMessageRecord: input.userMessageRecord,
203→        latestUserText: input.userText,
204→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
205→        ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
206→        messages: assistantContextRows.map((row) => ({
207→          role: row.role,
208→          text: row.text,
209→        })),
210→        onToken: async (token) => {
211→          input.deps.sse.emitEvent(input.messageId, {
212→            type: "token",
213→            messageId: input.messageId,
214→            token,
215→          });
216→        },
217→      });
218→
219→      assistantText = graphAwareResponse.text.trim();
220→    } else {
221→      const assistantReply = await generateOnboardingAssistantReply({
222→        assistantModel: input.deps.assistantModel,
223→        surreal: input.deps.surreal,
224→        onboardingState: onboardingAfter,
225→        contextRows: assistantContextRows,
226→        latestUserText: input.userText,
227→        workspaceRecord: input.workspaceRecord,
228→        latestEntities: persistedEntities.map((entity) => ({
229→          kind: entity.kind,
230→          text: entity.text,
231→          confidence: entity.confidence,
232→        })),
233→        latestTools: dedupedTools,
234→      });
235→
236→      assistantText = assistantReply.message.trim();
237→      assistantSuggestions = assistantReply.suggestions;
238→
239→      for (const token of assistantText.split(" ")) {
240→        input.deps.sse.emitEvent(input.messageId, {
241→          type: "token",
242→          messageId: input.messageId,
243→          token: `${token} `,
244→        });
245→        await new Promise((resolve) => setTimeout(resolve, 25));
246→      }
247→    }
248→
249→    assistantSuggestions = sanitizeAssistantSuggestions(
250→      [...assistantSuggestions, ...unresolvedAssigneeSuggestions],
251→      3,
252→    );
253→
254→    const summaryBlock = buildExtractionComponentBlock(
255→      persistedEntities,
256→      persistedRelationships,
257→      input.deps.config.extractionDisplayThreshold,
258→    );
259→
260→    if (summaryBlock) {
261→      if (onboardingAfter === "complete") {
262→        const streamChunk = assistantText.length > 0 ? `\n\n${summaryBlock}` : summaryBlock;
263→        for (const token of streamChunk.split(" ")) {
264→          input.deps.sse.emitEvent(input.messageId, {
265→            type: "token",
266→            messageId: input.messageId,
267→            token: `${token} `,
268→          });
269→        }
270→      }
271→
272→      assistantText = assistantText.length > 0 ? `${assistantText}\n\n${summaryBlock}` : summaryBlock;
273→    }
274→
275→    if (assistantText.trim().length === 0) {
276→      assistantText = "I could not generate a response for that request.";
277→    }
278→
279→    const assistantMessageRecord = new RecordId("message", input.messageId);
280→    await input.deps.surreal.create(assistantMessageRecord).content({
281→      conversation: conversationRecord,
282→      role: "assistant",
283→      text: assistantText,
284→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
285→      createdAt: now,
286→    });
287→
288→    await input.deps.surreal.update(conversationRecord).merge({
289→      updatedAt: now,
290→    });
291→
292→    void persistEmbeddings({
293→      surreal: input.deps.surreal,
294→      embeddingModel: input.deps.embeddingModel,
295→      embeddingDimension: input.deps.config.embeddingDimension,
296→      assistantMessageRecord,
297→      assistantText,
298→      entities: embeddingTargets,
299→    }).catch(() => undefined);
300→
301→    input.deps.sse.emitEvent(input.messageId, {
302→      type: "extraction",
303→      messageId: input.messageId,
304→      entities: persistedEntities,
305→      relationships: persistedRelationships,
306→    });
307→
308→    if (seedItems.length > 0) {
309→      input.deps.sse.emitEvent(input.messageId, {
310→        type: "onboarding_seed",
311→        messageId: input.messageId,
312→        seeds: seedItems,
313→      });
314→    }
315→
316→    if (onboardingBefore !== onboardingAfter) {
317→      input.deps.sse.emitEvent(input.messageId, {
318→        type: "onboarding_state",
319→        messageId: input.messageId,
320→        onboardingState: onboardingAfter,
321→      });
322→    }
323→
324→    input.deps.sse.emitEvent(input.messageId, {
325→      type: "assistant_message",
326→      messageId: input.messageId,
327→      text: assistantText,
328→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
329→    });
330→
331→    input.deps.sse.emitEvent(input.messageId, {
332→      type: "done",
333→      messageId: input.messageId,
334→    });
335→
336→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
337→      conversationId: input.conversationId,
338→      messageId: input.messageId,
339→      workspaceId: input.workspaceRecord.id as string,
340→      entityCount: persistedEntities.length,
341→      relationshipCount: persistedRelationships.length,
342→      seedCount: seedItems.length,
343→      durationMs: elapsedMs(startedAt),
344→    });
345→  } catch (error) {
346→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
347→      conversationId: input.conversationId,
348→      messageId: input.messageId,
349→      workspaceId: input.workspaceRecord.id as string,
350→      durationMs: elapsedMs(startedAt),
351→    });
352→    const errorText = userFacingError(error, "chat processing failed");
353→    input.deps.sse.emitEvent(input.messageId, {
354→      type: "error",
355→      messageId: input.messageId,
356→      error: errorText,
357→    });
358→  }
359→}
