361→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
362→  return [...new Set(suggestions.map((value) => value.trim()))]
363→    .filter((value) => value.length > 0 && value.length <= 140)
364→    .slice(0, limit);
365→}
