246→async function resolveWorkspaceBootstrapConversation(
247→  deps: ServerDependencies,
248→  workspaceRecord: RecordId<"workspace", string>,
249→): Promise<RecordId<"conversation", string>> {
250→  const [onboardingRows] = await deps.surreal
251→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
252→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
253→      {
254→        workspace: workspaceRecord,
255→      },
256→    )
257→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
258→
259→  if (onboardingRows.length > 0) {
260→    return onboardingRows[0].id;
261→  }
262→
263→  const [latestRows] = await deps.surreal
264→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
265→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
266→      {
267→        workspace: workspaceRecord,
268→      },
269→    )
270→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
271→
272→  if (latestRows.length > 0) {
273→    return latestRows[0].id;
274→  }
275→
276→  const now = new Date();
277→  const conversationRecord = new RecordId("conversation", randomUUID());
278→  await deps.surreal.create(conversationRecord).content({
279→    createdAt: now,
280→    updatedAt: now,
281→    workspace: workspaceRecord,
282→    source: "onboarding",
283→  });
284→  return conversationRecord;
285→}
