369→async function handleWorkspaceSidebar(deps: ServerDependencies, workspaceId: string): Promise<Response> {
370→  const startedAt = performance.now();
371→  logInfo("workspace.sidebar.started", "Workspace sidebar request started", { workspaceId });
372→
373→  try {
