400→async function handleWorkspaceConversation(
401→  deps: ServerDependencies,
402→  workspaceId: string,
403→  conversationId: string,
404→): Promise<Response> {
405→  const startedAt = performance.now();
406→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
407→    workspaceId,
408→    conversationId,
409→  });
410→
411→  try {
412→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
413→    const conversationRecord = new RecordId("conversation", conversationId);
414→    const conversation = await deps.surreal.select<{
415→      id: RecordId<"conversation", string>;
416→      workspace: RecordId<"workspace", string>;
417→    }>(conversationRecord);
418→
419→    if (!conversation) {
420→      throw new HttpError(404, `conversation not found: ${conversationId}`);
421→    }
422→
423→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
424→      throw new HttpError(400, "conversation does not belong to workspace");
425→    }
426→
427→    const [messageRows] = await deps.surreal
428→      .query<[MessageContextRow[]]>(
429→        "SELECT id, role, text, createdAt, suggestions FROM message WHERE conversation = $conversation ORDER BY createdAt ASC LIMIT 80;",
430→        { conversation: conversationRecord },
431→      )
432→      .collect<[MessageContextRow[]]>();
433→
434→    const messages = messageRows.map((row) => ({
435→      id: row.id.id as string,
436→      role: row.role,
437→      text: row.text,
438→      createdAt: toIsoString(row.createdAt),
439→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
440→    } satisfies WorkspaceBootstrapMessage));
441→
442→    const payload: WorkspaceConversationResponse = {
443→      conversationId,
444→      messages,
445→    };
446→
447→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
448→      workspaceId,
449→      conversationId,
450→      messageCount: messages.length,
451→      durationMs: elapsedMs(startedAt),
452→    });
453→
454→    return jsonResponse(payload, 200);
455→  } catch (error) {
456→    if (error instanceof HttpError) {
457→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
458→        workspaceId,
459→        conversationId,
460→        statusCode: error.status,
461→      });
462→      return jsonError(error.message, error.status);
463→    }
464→
465→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
466→      workspaceId,
467→      conversationId,
468→    });
469→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
470→    return jsonError(errorText, 500);
471→  }
472→}
