469→    if (isLoading || !workspace) {
470→      return;
471→    }
472→
473→    const text = message.trim();
474→    if (!text && !pendingFile) {
475→      return;
476→    }
477→
478→    setErrorMessage(undefined);
479→    setIsLoading(true);
480→    setSuggestions([]);
481→
482→    const clientMessageId = crypto.randomUUID();
483→    const currentAttachment = pendingFile;
484→
485→    setSessions((existing) =>
486→      existing.map((session) =>
487→        session.id === activeSessionId
488→          ? {
489→              ...session,
490→              updatedAt: new Date(),
491→              conversations: [
492→                ...session.conversations,
493→                {
494→                  id: clientMessageId,
495→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
496→                  createdAt: new Date(),
497→                  ...(currentAttachment
498→                    ? {
499→                        files: [
500→                          {
501→                            name: currentAttachment.name,
502→                            type: currentAttachment.type,
503→                            size: currentAttachment.size,
504→                          },
505→                        ],
506→                      }
507→                    : {}),
508→                },
509→              ],
510→            }
511→          : session,
512→      ),
513→    );
514→
515→    let response: Response;
516→    try {
517→      if (currentAttachment) {
518→        const formData = new FormData();
519→        formData.set("clientMessageId", clientMessageId);
520→        formData.set("workspaceId", workspace.id);
521→        formData.set("text", text);
522→        if (backendConversationId) {
523→          formData.set("conversationId", backendConversationId);
524→        }
525→        if (options?.onboardingAction) {
526→          formData.set("onboardingAction", options.onboardingAction);
527→        }
528→        formData.set("file", currentAttachment);
529→
530→        response = await fetch("/api/chat/messages", {
531→          method: "POST",
532→          body: formData,
533→        });
534→      } else {
535→        response = await fetch("/api/chat/messages", {
536→          method: "POST",
537→          headers: {
538→            "Content-Type": "application/json",
539→          },
540→          body: JSON.stringify({
541→            clientMessageId,
542→            workspaceId: workspace.id,
543→            text,
544→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
545→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
546→          }),
547→        });
548→      }
549→    } catch (error) {
550→      const messageText = error instanceof Error ? error.message : "Network error";
551→      setErrorMessage(messageText);
552→      setIsLoading(false);
553→      return;
554→    } finally {
555→      setPendingFile(undefined);
556→    }
557→
558→    if (!response.ok) {
559→      const body = await response.text();
560→      setErrorMessage(body);
561→      setIsLoading(false);
562→      return;
563→    }
564→
565→    const payload = (await response.json()) as ChatMessageResponse;
566→    const isNewConversation = !backendConversationId;
567→    setBackendConversationId(payload.conversationId);
568→    if (isNewConversation) {
569→      setActiveConversationId(payload.conversationId);
570→    }
571→
572→    if (streamRef.current) {
573→      streamRef.current.close();
574→      streamRef.current = undefined;
575→    }
576→
577→    let streamedText = "";
578→
579→    const stream = new EventSource(payload.streamUrl);
580→    streamRef.current = stream;
581→
582→    stream.onmessage = (messageEvent) => {
583→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
584→
585→      if (parsed.type === "token") {
586→        streamedText = `${streamedText}${parsed.token}`;
587→        setSessions((existing) =>
588→          existing.map((session) =>
589→            session.id === activeSessionId
590→              ? {
591→                  ...session,
592→                  conversations: session.conversations.map((conversation) =>
593→                    conversation.id === clientMessageId
594→                      ? {
595→                          ...conversation,
596→                          response: streamedText,
597→                          updatedAt: new Date(),
598→                        }
599→                      : conversation,
600→                  ),
601→                }
602→              : session,
603→          ),
604→        );
605→        return;
606→      }
607→
608→      if (parsed.type === "extraction") {
609→        setSeedItems((existing) => {
610→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
611→          for (const entity of parsed.entities) {
612→            const key = `${entity.id}:${entity.sourceKind}:${entity.sourceId}`;
613→            if (!deduped.has(key)) {
614→              deduped.set(key, {
615→                id: entity.id,
616→                kind: entity.kind,
617→                text: entity.text,
618→                confidence: entity.confidence,
619→                sourceKind: entity.sourceKind,
620→                sourceId: entity.sourceId,
621→              });
622→            }
623→          }
624→          return [...deduped.values()];
625→        });
626→        return;
627→      }
628→
629→      if (parsed.type === "assistant_message") {
630→        streamedText = parsed.text;
631→        setSuggestions(
632→          (parsed.suggestions ?? []).map((content, index) => ({
633→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
634→            content,
635→          })),
636→        );
637→        setSessions((existing) =>
638→          existing.map((session) =>
639→            session.id === activeSessionId
640→              ? {
641→                  ...session,
642→                  conversations: session.conversations.map((conversation) =>
643→                    conversation.id === clientMessageId
644→                      ? {
645→                          ...conversation,
646→                          response: streamedText,
647→                          updatedAt: new Date(),
648→                        }
649→                      : conversation,
650→                  ),
651→                }
652→              : session,
653→          ),
654→        );
655→        return;
656→      }
657→
658→      if (parsed.type === "onboarding_seed") {
659→        setSeedItems((existing) => {
660→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
661→          for (const seed of parsed.seeds) {
662→            deduped.set(`${seed.id}:${seed.sourceKind}:${seed.sourceId}`, seed);
663→          }
664→          return [...deduped.values()];
665→        });
666→        return;
667→      }
668→
669→      if (parsed.type === "onboarding_state") {
670→        setWorkspace((existing) =>
671→          existing
672→            ? {
673→                ...existing,
674→                onboardingState: parsed.onboardingState,
675→                onboardingComplete: parsed.onboardingState === "complete",
676→              }
677→            : existing,
678→        );
679→        return;
680→      }
681→
682→      if (parsed.type === "error") {
683→        setErrorMessage(parsed.error);
684→        setIsLoading(false);
685→        stream.close();
686→        streamRef.current = undefined;
687→        return;
688→      }
689→
690→      if (parsed.type === "done") {
691→        setSessions((existing) =>
692→          existing.map((session) =>
693→            session.id === activeSessionId
694→              ? {
695→                  ...session,
696→                  updatedAt: new Date(),
697→                  conversations: session.conversations.map((conversation) =>
698→                    conversation.id === clientMessageId
699→                      ? {
700→                          ...conversation,
701→                          response: streamedText,
702→                          updatedAt: new Date(),
703→                        }
704→                      : conversation,
705→                  ),
706→                }
707→              : session,
708→          ),
709→        );
710→
711→        setIsLoading(false);
712→        stream.close();
713→        streamRef.current = undefined;
714→
715→        // Refresh sidebar after stream completes
716→        if (workspace) {
717→          void refreshSidebar(workspace.id);
718→        }
719→      }
720→    };
721→
722→    stream.onerror = () => {
723→      setErrorMessage("SSE stream disconnected");
724→      setIsLoading(false);
725→      stream.close();
726→      streamRef.current = undefined;
727→    };
728→  }
