 1→import { stepCountIs, streamText, type ModelMessage } from "ai";
 2→import { RecordId, Surreal } from "surrealdb";
 3→import { buildChatContext, buildSystemPrompt } from "./context";
 4→import { createOrchestratorTools } from "./tools";
 5→
 6→type ConversationMessage = {
 7→  role: "user" | "assistant";
 8→  text: string;
 9→};
10→
11→export async function runOrchestrator(input: {
12→  surreal: Surreal;
13→  model: any;
14→  pmModel: any;
15→  embeddingModel: any;
16→  embeddingDimension: number;
17→  extractionModelId: string;
18→  conversationRecord: RecordId<"conversation", string>;
19→  workspaceRecord: RecordId<"workspace", string>;
20→  currentMessageRecord: RecordId<"message", string>;
21→  latestUserText: string;
22→  workspaceOwnerRecord?: RecordId<"person", string>;
23→  inheritedEntityIds?: RecordId[];
24→  messages: ConversationMessage[];
25→  onToken: (token: string) => Promise<void> | void;
26→}): Promise<{ text: string }> {
27→  const context = await buildChatContext({
28→    surreal: input.surreal,
29→    conversationRecord: input.conversationRecord,
30→    workspaceRecord: input.workspaceRecord,
31→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
32→      ? { inheritedEntityIds: input.inheritedEntityIds }
33→      : {}),
34→  });
35→
36→  const system = buildSystemPrompt(context);
37→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
38→    role: message.role,
39→    content: message.text,
40→  }));
41→
42→  const result = streamText({
43→    model: input.model,
44→    system,
45→    messages: modelMessages,
46→    tools: createOrchestratorTools({
47→      surreal: input.surreal,
48→      pmModel: input.pmModel,
49→      embeddingModel: input.embeddingModel,
50→      embeddingDimension: input.embeddingDimension,
51→      extractionModelId: input.extractionModelId,
52→    }),
53→    experimental_context: {
54→      actor: "orchestrator",
55→      workspaceRecord: input.workspaceRecord,
56→      conversationRecord: input.conversationRecord,
57→      currentMessageRecord: input.currentMessageRecord,
58→      latestUserText: input.latestUserText,
59→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
60→    },
61→    stopWhen: stepCountIs(5),
62→  });
63→
64→  let text = "";
65→  for await (const part of result.fullStream) {
66→    if (part.type !== "text-delta") {
67→      continue;
68→    }
69→
70→    text = `${text}${part.text}`;
71→    await input.onToken(part.text);
72→  }
73→
74→  if (text.trim().length === 0) {
75→    text = await result.text;
76→  }
77→
78→  return {
79→    text: text.trim(),
80→  };
81→}
82→
83→export const runGraphAwareChat = runOrchestrator;
