133→// ── Entity-to-project resolution ────────────────────────────────────────
134→
135→type ExtractionEdgeRow = {
136→  out: GraphEntityRecord;
137→  extracted_at: Date | string;
138→};
139→
140→type BelongsToRow = {
141→  out: RecordId<string, string> & { tb: string };
142→};
143→
144→type HasFeatureRow = {
145→  in: RecordId<"project", string>;
146→};
147→
148→/**
149→ * Resolves which project(s) an extracted entity belongs to.
150→ * Returns a map of projectId -> { entityIds, earliestExtractedAt }.
151→ */
152→async function resolveEntityToProjects(
153→  surreal: Surreal,
154→  entityRecord: GraphEntityRecord,
155→): Promise<RecordId<"project", string>[]> {
156→  const table = entityRecord.tb;
157→
158→  if (table === "project") {
159→    return [entityRecord as unknown as RecordId<"project", string>];
160→  }
161→
162→  if (table === "feature") {
163→    const [rows] = await surreal
164→      .query<[HasFeatureRow[]]>(
165→        "SELECT `in` FROM has_feature WHERE out = $feature;",
166→        { feature: entityRecord },
167→      )
168→      .collect<[HasFeatureRow[]]>();
169→    return rows.map((row) => row.in);
170→  }
171→
172→  if (table === "task" || table === "decision" || table === "question") {
173→    const [belongsToRows] = await surreal
174→      .query<[BelongsToRow[]]>(
175→        "SELECT out FROM belongs_to WHERE `in` = $entity;",
176→        { entity: entityRecord },
177→      )
178→      .collect<[BelongsToRow[]]>();
179→
180→    const projects: RecordId<"project", string>[] = [];
181→
182→    for (const row of belongsToRows) {
183→      if (row.out.tb === "project") {
184→        projects.push(row.out as RecordId<"project", string>);
185→      } else if (row.out.tb === "feature") {
186→        const [featureRows] = await surreal
187→          .query<[HasFeatureRow[]]>(
188→            "SELECT `in` FROM has_feature WHERE out = $feature;",
189→            { feature: row.out },
190→          )
191→          .collect<[HasFeatureRow[]]>();
192→        projects.push(...featureRows.map((r) => r.in));
193→      }
194→    }
195→
196→    return projects;
197→  }
198→
199→  // person, workspace, and other kinds do not contribute
200→  return [];
201→}
