203→// ── Database operations ─────────────────────────────────────────────────
204→
205→type TouchedByRow = {
206→  id: RecordId<"touched_by", string>;
207→  in: RecordId<"project", string>;
208→  out: RecordId<"conversation", string>;
209→  entity_count: number;
210→  first_mention_at: Date | string;
211→};
