408→// ── Sidebar builder ─────────────────────────────────────────────────────
409→
410→type ConversationSidebarRow = {
411→  id: RecordId<"conversation", string>;
412→  title?: string;
413→  updatedAt: Date | string;
414→};
415→
416→type FeatureActivityRow = {
417→  featureId: RecordId<"feature", string>;
418→  featureName: string;
419→  latestActivityAt: Date | string;
420→};
421→
422→type BranchedFromRow = {
423→  in: RecordId<"conversation", string>;
424→  out: RecordId<"conversation", string>;
425→};
426→
427→/**
428→ * Recursively attaches branch conversations to their parent items.
429→ */
430→function attachBranches(
431→  item: ConversationSidebarItem,
432→  childrenMap: Map<string, ConversationSidebarItem[]>,
433→): ConversationSidebarItem {
434→  const children = childrenMap.get(item.id);
435→  if (!children || children.length === 0) return item;
436→  return {
437→    ...item,
438→    branches: children.map((child) => attachBranches(child, childrenMap)),
439→  };
440→}
