 58→export async function loadConversationGraphContext(
 59→  surreal: Surreal,
 60→  conversationId: string,
 61→  limit: number,
 62→  options?: { inheritedEntityIds?: RecordId[] },
 63→): Promise<ExtractionGraphContextRow[]> {
 64→  const conversationRecord = new RecordId("conversation", conversationId);
 65→  const [rows] = await surreal
 66→    .query<[ConversationProvenanceRow[]]>(
 67→      [
 68→        "SELECT `in`, out, confidence, extracted_at",
 69→        "FROM extraction_relation",
 70→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
 71→        "ORDER BY extracted_at DESC",
 72→        "LIMIT $limit;",
 73→      ].join(" "),
 74→      { conversation: conversationRecord, limit },
 75→    )
 76→    .collect<[ConversationProvenanceRow[]]>();
 77→
 78→  const seen = new Set<string>();
 79→  const items: ExtractionGraphContextRow[] = [];
 80→
 81→  for (const row of rows) {
 82→    const entityId = row.out.id as string;
 83→    if (seen.has(entityId)) {
 84→      continue;
 85→    }
 86→
 87→    const entityTable = row.out.tb;
 88→    if (
 89→      entityTable !== "project" &&
 90→      entityTable !== "person" &&
 91→      entityTable !== "feature" &&
 92→      entityTable !== "task" &&
 93→      entityTable !== "decision" &&
 94→      entityTable !== "question"
 95→    ) {
 96→      continue;
 97→    }
 98→
 99→    const entityText = await readEntityText(surreal, row.out);
100→    if (!entityText) {
101→      continue;
102→    }
103→
104→    items.push({
105→      id: row.out,
106→      kind: entityTable as ExtractableEntityKind,
107→      text: entityText,
108→      confidence: row.confidence,
109→      sourceMessage: row.in,
110→    });
111→    seen.add(entityId);
112→  }
113→
114→  // Merge inherited entities from parent conversation when branch has sparse context
115→  if (options?.inheritedEntityIds && options.inheritedEntityIds.length > 0 && items.length < 5) {
116→    const [inheritedRows] = await surreal
117→      .query<[ConversationProvenanceRow[]]>(
118→        [
119→          "SELECT `in`, out, confidence, extracted_at",
120→          "FROM extraction_relation",
121→          "WHERE out IN $entityIds",
122→          "ORDER BY extracted_at DESC",
123→          "LIMIT $limit;",
124→        ].join(" "),
125→        { entityIds: options.inheritedEntityIds, limit },
126→      )
127→      .collect<[ConversationProvenanceRow[]]>();
128→
129→    for (const row of inheritedRows) {
130→      const entityId = row.out.id as string;
131→      if (seen.has(entityId)) continue;
132→
133→      const entityTable = row.out.tb;
134→      if (
135→        entityTable !== "project" &&
136→        entityTable !== "person" &&
137→        entityTable !== "feature" &&
138→        entityTable !== "task" &&
139→        entityTable !== "decision" &&
140→        entityTable !== "question"
141→      ) {
142→        continue;
143→      }
144→
145→      const entityText = await readEntityText(surreal, row.out);
146→      if (!entityText) continue;
147→
148→      items.push({
149→        id: row.out,
150→        kind: entityTable as ExtractableEntityKind,
151→        text: entityText,
152→        confidence: row.confidence,
153→        sourceMessage: row.in,
154→      });
155→      seen.add(entityId);
156→    }
157→  }
158→
159→  return items;
160→}
