      workspaceId,
      parentConversationId,
      branchId,
      branchPointMessageId: parsed.data.messageId,
    });

    const response: BranchConversationResponse = {
      conversationId: branchId,
      parentConversationId,
      branchPointMessageId: parsed.data.messageId,
