    latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
  }

  setSessions([
    {
      id: "main",
      title: payload.workspaceName,
      createdAt: new Date(),
      updatedAt: new Date(),
      conversations,
    },
  ]);

